# -*- coding: utf-8 -*-
import subprocess

def execute_tool(command: str, timeout: int = 30):
    try:
        result = subprocess.run(
            command, 
            shell=True, 
            capture_output=True, 
            text=True, 
            timeout=timeout,
            encoding='utf-8',
            errors='ignore'
        )
        if result.returncode == 0:
            return result.stdout
        else:
            return f"错误: {result.stderr}\n返回码: {result.returncode}"
    except subprocess.TimeoutExpired:
        return "错误: 命令执行超时"
    except Exception as e:
        return f"错误: {str(e)}"
